INSERT INTO offmarket.business_signals (business_id,layer,signal_key,direction,evidence,source,source_url,observed_at) VALUES
('b6b1dd46-baed-53bb-b656-66532580668c', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 21 yrs in business per company website/search. Owner age estimate 52 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', NULL, '2026-05-15'),('607cae1f-3b54-5139-b61a-7e39fd497312', 3, 'successor_check_live_fetch', 'disqualifying', 'Live homepage shows generic copy with no team names. Per protocol — no live team-page identifies any specific individual = cap at C_watch. (Family ownership confirmed by BBB but no successor evidence.)', 'web_search_synthesis', 'https://bewleyelectric.com/', '2026-05-15'),('607cae1f-3b54-5139-b61a-7e39fd497312', 3, 'no_ev_charger_service', 'positive', 'Site does not list EV-charger install services. In 2026 TX metros, this is a coasting tell — every healthy residential electrical shop offers EV-charger install.', 'live_website_fetch', 'https://bewleyelectric.com/', '2026-05-15'),('607cae1f-3b54-5139-b61a-7e39fd497312', 3, 'no_online_booking', 'positive', 'Site does not offer online booking integration (no Housecall Pro / ServiceTitan / Yapi visible).', 'live_website_fetch', 'https://bewleyelectric.com/', '2026-05-15'),('6149261c-c11c-5626-b2fc-40d675290b48', 3, 'successor_check_live_fetch', 'negative', '5+ Master Electricians on staff = multiple internal successor candidates. Per protocol, this is internal-buy-in territory, not off-market acquire-self.', 'web_search_synthesis', 'https://colvinelectric.com/', '2026-05-15'),('6149261c-c11c-5626-b2fc-40d675290b48', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 44 yrs in business per company website/search. Owner age estimate 65 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', 'https://colvinelectric.com/', '2026-05-15'),('65953bd1-e4a2-5152-aaa1-31c42c1ddf53', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 65 yrs in business per company website/search. Owner age estimate 72 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', 'https://www.mcbrideelectric.com/', '2026-05-15'),('2420c81c-c56d-5517-845f-c2d3b1ca9de0', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 47 yrs in business per company website/search. Owner age estimate 65 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', 'https://spehouston.com/home', '2026-05-15'),('83b3b6ee-c110-5bd1-bc33-c9e76d41af0a', 3, 'successor_check_live_fetch', 'negative', '3rd-gen Walding family + 4 Master Electricians on staff. Multiple internal successors. NOT off-market target.', 'web_search_synthesis', 'https://www.dentonelectricinc.com/', '2026-05-15'),('83b3b6ee-c110-5bd1-bc33-c9e76d41af0a', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 104 yrs in business per company website/search. Owner age estimate 72 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', 'https://www.dentonelectricinc.com/', '2026-05-15'),('4ee1b8ca-4eef-5027-bf7c-2cdd3f85e86d', 3, 'successor_check_live_fetch', 'disqualifying', 'No live team page found. Yelp/Procore only. Per protocol cap at C_watch.', 'web_search_synthesis', NULL, '2026-05-15');